import{_ as p,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const D=JSON.parse('{"title":"通用忍术","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/能量类/忍术/通用忍术.md","filePath":"4.资源分区/6.技艺及称号/能量类/忍术/通用忍术.md"}'),s={name:"4.资源分区/6.技艺及称号/能量类/忍术/通用忍术.md"};function o(d,b,l,_,i,c){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"通用忍术",tabindex:"-1"},[t("通用忍术 "),r("a",{class:"header-anchor",href:"#通用忍术","aria-label":'Permalink to "通用忍术"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),n('<h1 id="通用忍术-1" tabindex="-1">通用忍术 <a class="header-anchor" href="#通用忍术-1" aria-label="Permalink to &quot;通用忍术&quot;">​</a></h1><p>通用忍术</p><p>【分身术】<br> 价格：D+500<br> 消耗能量：2点<br> 使用动作：迅捷<br> 遁术性质：无<br> 持续时间：立即<br> 目标：自身<br> 忍术成分：姿势、语言、忍印<br> 距离：触及<br> 描述：忍者学校级的忍术，难度最低。三身术之一</p><p>效果：使用者被视作攻击对象时，进行一个忍术鉴定，制造出一个自己的分身，这是一个D级幻象来源，对方需进行一次侦察鉴定对抗。如失败则对方对使用者的攻击会承受等于失败数的DP减值，上限为7点。</p><p>【替身术】<br> 价格：D+500<br> 消耗能量：2点<br> 使用动作：反射+本轮内仍有的移动动作<br> 遁术性质：无<br> 持续时间：立即<br> 目标：自身<br> 忍术成分：姿势、忍印<br> 距离：15米<br> 描述：忍者学校级的忍术，难度最低。三身术之一</p><p>效果：当你被对方视为攻击对象时，会移动到距离你原先位置15米的距离，这次移动具有打断性，并获得5点遮蔽防御。</p><p>【变身术】<br> 价格：D+500<br> 消耗能量：2点<br> 使用动作：标准<br> 遁术性质：无<br> 持续时间：一场景<br> 目标：自身<br> 忍术成分：姿势、语言、忍印<br> 距离：触及<br> 描述：忍者学校级的忍术，难度最低。三身术之一</p><p>效果：进行一个操控+隐秘+伪装的检定，记录此成功数。<br> 接着，你可以将你的面貌、性别、服装按照自我意愿进行塑造。当他人试图认出你的原本样貌时，其需以进行一个以识破伪装为目的的调查检定，DC为你先前的成功数+2，这是一个D级幻象来源的伪装效果。</p><p>【色诱术】<br> 价格：D+500<br> 消耗能量：2点<br> 使用动作：标准<br> 遁术性质：无<br> 持续时间：一场景<br> 目标：自身<br> 忍术成分：姿势、语言、忍印<br> 距离：触及</p><p>描述：鸣人自创的变身忍术，由施术者变成有云雾缭绕着的全裸美女，除了漂亮的脸蛋，最重要的是变化后的身体比例。<br> 后来，此术传给了木叶丸三人组。此术可以变化为美女，也可以是美男子，更可以是兽类。</p><p>效果：进行一次忍术检定，对方进行一次意志豁免，如失败，则获得失败值的魅惑点数，标准豁免，如果你此时的性别与对方的性取向相同，则其还会受到1点不可豁免的魅惑点数。</p><p>【响鸣穿】<br> D+500<br> 消耗能量：2点<br> 使用动作：标准<br> 遁术性质：无<br> 持续时间：立即<br> 目标：敌方单体<br> 忍术成分：姿势、语言、忍印<br> 距离：操控*2米<br> 描述：利用特殊的器具发出声音的忍术，就算没直接攻击到对手也可以经由震动来伤害对手的鼓膜和三半规管，即使把耳朵堵住都毫无用处。</p><p>效果：对目标进行一次忍术攻击检定，造成音波伤害，强韧豁免。攻击附带耳鸣伤害点的异常点数，正常豁免，并获得不可豁免的耳鸣点数1点。</p><p>【潜影蛇手】<br> 价格：C+1000<br> 消耗能量：4点<br> 使用动作：标准<br> 遁术性质：无<br> 持续时间：立即<br> 目标：扇形区域内的敌方单位<br> 忍术成分：姿势、语言<br> 距离：触及<br> 描述：从手上放出蛇攻击对方</p><p>效果：进行一次近战攻击检定，这次攻击触及距离+10米，造成腐蚀伤害，具有吸血3。</p><p>【毒雾】<br> C+1000<br> 消耗能量：6点<br> 使用动作：标准<br> 遁术性质：无<br> 持续时间：一回合<br> 目标：扇形群体<br> 忍术成分：姿势、忍印<br> 距离：45米<br> 描述：将体内的查克拉变化为特殊的化学物质从口中吐出，这种物质与空气接触瞬间会变为紫色的剧毒的雾，即使是吸入一点那也会是致命伤。</p><p>效果：进行一次忍术攻击检定，这次攻击造成腐蚀伤害，目标以强韧豁免。受到伤害的单位会承受1点不可豁免的毒素点数。在这次攻击使用后的一轮内，如果有敌方单位进入此区域，其也会受到本攻击影响。<br> 若对方不需要呼吸或捂住口鼻，则此技能造成的伤害减半。</p><p>【蛤蟆油弹】<br> C+1000<br> 消耗能量：6点<br> 使用动作：标准<br> 遁术性质：无<br> 持续时间：一轮<br> 目标：扇形群体<br> 忍术成分：姿势、语言、忍印<br> 距离：30米<br> 描述：将体内练成的查克拉转化为油，使之成为巨大的块状物一次吐出的忍术。由于油的粘着性很高，目标被击中的瞬间就会覆盖一层油膜并封住其行动力。</p><p>效果：前方扇形30米在一轮内形成C级环境来源的困难地形区域。<br> 对范围内敌人进行一次忍术攻击检定，目标以反射豁免。失败则承受差值+3点的火焰易伤点数，和一点受到其他火焰伤害时的附加成功。<br> 火焰易伤在受到一次火焰伤害后消失。</p><p>差价升级至B+2000<br> 能量消耗提升至10<br> 作用范围提升至60米<br> 效果提升火焰易伤现在在受到2次火焰伤害后才消失</p><p>【掌仙术】<br> C+1000<br> 消耗能量：6点<br> 使用动作：标准<br> 遁术性质：无<br> 持续时间：一回合<br> 目标；一个单位<br> 忍术成分：姿势、语言、忍印<br> 距离：触及<br> 描述：不论内伤外伤都可靠放出的查克拉达到惊异的回复速度。即使在医疗班中，能使用的人也是极少数。也可借由放出的查克拉干扰他人身体内查克拉的循环，造成昏睡状态等等的超高等忍术。</p><p>效果：选定一个目标，目标在一轮内获得3快速医疗（医疗点数：44）并恢复2点异常点数（医疗点数48）<br> 或者进行一次忍术攻击检定，这次攻击具有4DP技艺加值，造成纯能量严重伤害，受到伤害的目标在一轮内使用能力的能量消耗提升2点。</p><p>【螺旋丸】<br> C+1000<br> 消耗能量：6点<br> 使用动作：标准+迅捷<br> 遁术性质：无<br> 持续时间：立即<br> 目标：单体<br> 忍术成分：姿势、语言、忍印<br> 距离：触及范围<br> 描述：螺旋丸是将查克拉凝聚在手上，令查克拉以不同的方向不停流动并加以压缩，形成高旋转密度的“查克拉球”，具有极大的破坏力。</p><p>效果：进行一次忍术接触攻击检定，这次攻击附带使用者操控属性点能量加值，目标需要使用强韧豁免，失败则受到差额伤害。<br> 特殊的，螺旋丸在花费迅捷动作凝聚后可以选择令其维持在手中至多三轮，维持螺旋丸会导致你无法使用其他忍术，直到你以标准动作将其打出。</p><p>差价升级至B+2000<br> 消耗能量：10点<br> 使用动作：标准<br> 遁术性质：无<br> 持续时间：立即<br> 目标：单体<br> 忍术成分：姿势、语言、忍印<br> 距离：触及范围</p><p>效果：进行一次忍术接触攻击检定，这次攻击附带使用者操控属性点能量加值与破魔10、威猛5，目标需要使用强韧豁免，失败则受到差额伤害。<br> 目标受到螺旋丸伤害以后，会在一轮内因为螺旋丸的巨大威力而无法以肢体进行移动，这是一个B级创伤来源的肢体残障效果。<br> 特殊的，螺旋丸在花费标准动作凝聚后可以选择令其维持在手中至多三轮，维持螺旋丸会导致你无法使用其他忍术，直到你以自由动作（若是回合外需要你使用反射动作）将其打出。</p><p>【影分身】<br> 价格：B+2000<br> 消耗能量：10<br> 使用动作：标准<br> 遁术性质：无<br> 持续时间：一场景/十分钟<br> 目标：自身<br> 忍术成分：姿势、语言、忍印<br> 距离：触及<br> 描述：消耗查克拉制造出一个与自身几乎相同的影分身，其具有自己的大部分能力并且可以自主的进行活动。</p><p>效果：制造出一个与自己一摸一样的影分身，他人若想分辨你本体与影分身的区别，需要以迅捷动作用自身的侦查检定对抗你的【操控+隐秘+伪装】检定，若成功即可分辨出你的本体。特殊的，若一个单位免疫B级幻象来源的负面效果，他也能立刻分辨出你的本体。<br> 影分身具有以下能力：<br> 1、影分身每轮具有一个移动动作与标准动作。其移动动作只能进行基础规则中允许的行为。标准动作可以使用招式进行攻击，但不会享受任何招式所带来的好处，他人如果能识破影分身与本体的区别，会发现影分身的招式实质上只是一次普通攻击。<br> 2、使用与本体相同的先攻，与本体共同行动。影分身的属性、技能、专业、攻击、防御属性均与本体一致。影分身消耗的能量均由本体支付。<br> 3、影分身受到任何伤害、异常点数、异常状态会立即消散。<br> 4、影分身于非战斗中可进行修炼，每累计修炼一个小时，影分身会获得1xp，这部分xp只能用于购买忍术与属性、技能、专业。修炼期间所获得的收益会在影分身解除后回归本体。本体每影片至多从影分身上获得4xp。</p><p>【针地藏】<br> B+2000<br> 消耗能量：10点<br> 使用动作：标准<br> 遁术性质：无<br> 持续时间：一轮<br> 目标：自身<br> 忍术成分：姿势、语言、忍印<br> 距离：5米<br> 描述：秘传防御忍术，将自己的银色长发硬化变成针刺的状态，伸展开后如同针衣一般包裹住自己的整个身体进行防御。</p><p>效果：进行一次全防御，获得12点天生防御与来自天生防御的3点附加成功，对方对你进行近战攻击时可反伤3点严重穿刺伤害与不可豁免的流血点数3点。</p><p>【乱狮子发之术】<br> B+2000<br> 消耗能量：10点<br> 使用动作：标准<br> 遁术性质：无<br> 持续时间：特殊<br> 目标：敌方单体<br> 忍术成分：姿势、语言、忍印<br> 距离：操控*2米<br> 描述：把头发变长，形成狮子头状把对方缠住，力度足以切碎对方。</p><p>效果：以忍术攻击检定进行一次擒抱命中检定，正常对抗。<br> 接着，你在后续的擒抱对抗/压制行为中可以用操控+专注+忍术代替力量+武技+肉搏专业进行检定。<br> 你在一轮内的擒抱相关行为获得6DP技艺加值，获得基于技艺的1点附加成功。<br> 对方处于该忍术导致的擒抱状态一轮后，会受到不可豁免的5点钝击伤害。</p><p>【阴封印】<br> 价格：B+2000<br> 消耗能量：无<br> 使用动作：被动<br> 遁术性质：无<br> 持续时间：永久<br> 目标：自身<br> 忍术成分：无<br> 距离：自身<br> 描述：第五代火影·纲手开发的S级医疗型封印术，施术者结印后额头上出现菱形标记，微调节查克拉，达到瞬间治愈和加强攻击，提高速度的效果，熟练运用者更可以靠百豪之印内查克拉的低输出和微调节达到驻颜青春，提高身体机能，使身体机能保持在全盛状态的效果。<br> 这个兑换，只有在称号：木叶忍者中选择了医疗忍者技艺才可以兑换。<br> 获得这个忍术之后，只要你的查克拉能量池不为空，你就具有A级别的衰老免疫效果。只要你在一场影片中，没有使用过【百豪之术·创造再生】，那么你在这场影片结束后，由于日常对于查克拉的积累，会额外获得查克拉能量池等级*1点的快速医疗（医疗点查克拉能量池等级*12+24点），这个效果最多获得两次。</p><p>【百豪之术·创造再生】<br> 价格：A+4000<br> 消耗能量：14<br> 使用动作：标准<br> 遁术性质：无<br> 持续时间：一个场景<br> 目标：自身<br> 忍术成分：语言<br> 距离：自身<br> 描述：第五代火影·纲手开发的S级医疗忍术，将平时储存在阴封印之中的查克拉解放。发动时咒印遍布全身，受到伤害的瞬间开始持续迅速的高速自动再生而不影响攻击节奏。<br> 这个兑换，需要兑换【阴封印】作为前提。<br> 发动这个忍术后，在这个场景内，你额外具有8点快速医疗（医疗点96），并且你可以立即再生你的四肢（包括头部）。<br> 由于你现在具有的恐怖的再生能力，只要你的查克拉池不为空，在这个场景内你具有免疫A级重伤的效果。同时你快速地对于肉体进行再生，可以基本上免于大多数试图对你行动进行干扰的手段，你免疫A级别的创伤来源的效果。<br> 在这个场景中，一回合一次，你可以在受到伤害之后迅速对肉体进行再生，使得这次伤害减少至原先的一半。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',36)])])}const f=p(s,[["render",o]]);export{D as __pageData,f as default};
